import { PieChart, Pie, Cell } from "recharts";

const data = [
  { name: "Remember", value: 3 },
  { name: "Understand", value: 4 },
  { name: "Apply", value: 4 },
  { name: "Analyze", value: 3 },
  { name: "Evaluate", value: 3 },
  { name: "Create", value: 3 },
];

const COLORS = [
  "#3b82f6",
  "#06b6d4",
  "#10b981",
  "#f59e0b",
  "#f97316",
  "#8b5cf6",
];

export default function Dashboard() {
  return (
    <div className="space-y-6">
      {/* Cards */}
      <div className="grid grid-cols-4 gap-4">
        <Card title="Total Questions" value="20" />
        <Card title="Higher-Order" value="35%" />
        <Card title="Files" value="1" />
        <Card title="Confidence" value="85%" />
      </div>

      {/* Charts */}
      <div className="grid grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow">
          <h3 className="mb-4 font-medium">Bloom Distribution</h3>
          <PieChart width={300} height={300}>
            <Pie data={data} dataKey="value">
              {data.map((_, i) => (
                <Cell key={i} fill={COLORS[i]} />
              ))}
            </Pie>
          </PieChart>
        </div>

        <div className="bg-white p-6 rounded-xl shadow space-y-4">
          <h3 className="font-medium">Quick Actions</h3>

          <button className="w-full bg-green-600 text-white py-2 rounded">
            Upload New Question Set
          </button>

          <button className="w-full border py-2 rounded">View Analysis</button>
        </div>
      </div>
    </div>
  );
}

function Card({ title, value }) {
  return (
    <div className="bg-white p-4 rounded-xl shadow">
      <p className="text-gray-500">{title}</p>
      <h2 className="text-xl font-bold">{value}</h2>
    </div>
  );
}
